solutions.python:
class Solution:
    def countPoints(self, rings: str) -> int:
        colors = [set() for _ in range(10)]
        for i in range(0, len(rings), 2):
            c = rings[i]
            rod = int(rings[i + 1])
            colors[rod].add(c)
        return sum(1 for s in colors if len(s) == 3)

solutions.javascript:
var countPoints = function(rings) {
    const colors = Array.from({ length: 10 }, () => new Set());
    for (let i = 0; i < rings.length; i += 2) {
        const c = rings[i];
        const rod = parseInt(rings[i + 1], 10);
        colors[rod].add(c);
    }
    let count = 0;
    for (const s of colors) if (s.size === 3) count++;
    return count;
};
